import React from 'react'
import { GameRunningStatus } from '../types'

/**
 * Return elapsed time (milliseconds) in game.
 */
export function useElapsedTime(
  status: GameRunningStatus,
  initialUsedTime = 0,
  initialStatus: GameRunningStatus.PENDING | GameRunningStatus.PAUSED = GameRunningStatus.PENDING,
): number {
  // Timestamp of the last time the timer started.
  const lastStartTimeRef = React.useRef<number>(-1)

  // Previous game status.
  const prevStatusRef = React.useRef<GameRunningStatus>(initialStatus)

  // Cumulative use of time.
  const usedTimeRef = React.useRef<number>(initialUsedTime)

  const prevStatus = prevStatusRef.current
  prevStatusRef.current = status

  switch (status) {
    case GameRunningStatus.PENDING:
      return 0
    case GameRunningStatus.RUNNING: {
      switch (prevStatus) {
        case GameRunningStatus.PENDING:
          usedTimeRef.current = 0
          lastStartTimeRef.current = Date.now()
          return 0
        case GameRunningStatus.RUNNING:
          return usedTimeRef.current + Date.now() - lastStartTimeRef.current
        case GameRunningStatus.PAUSED:
          lastStartTimeRef.current = Date.now()
          return usedTimeRef.current
        case GameRunningStatus.FINISHED:
          usedTimeRef.current = 0
          lastStartTimeRef.current = Date.now()
          return 0
        default:
          return usedTimeRef.current
      }
    }
    case GameRunningStatus.PAUSED: {
      if (prevStatus === GameRunningStatus.RUNNING) {
        usedTimeRef.current += Date.now() - lastStartTimeRef.current
      }
      return usedTimeRef.current
    }
    case GameRunningStatus.FINISHED: {
      if (prevStatus === GameRunningStatus.RUNNING) {
        usedTimeRef.current += Date.now() - lastStartTimeRef.current
      }
      return usedTimeRef.current
    }
    default:
      throw new TypeError(`[usedRecordTime] expect a GameRunningState, but got (${status})`)
  }
}

export default useElapsedTime
